import { useDispatch, useSelector } from "react-redux";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faCheck, faCartShopping, faTrash } from "@fortawesome/free-solid-svg-icons";
import { removeShoppingItem, toggleShoppingItem } from "./shoppingListSlice";

export default function ShoppingListPage() {
  const dispatch = useDispatch();
  const items = useSelector((state) => state.shoppingList.items);

  return (
    <div className="page-stack">
      <div className="page-heading">
        <p className="eyebrow">Shopping list</p>
        <h2><FontAwesomeIcon icon={faCartShopping} /> Missing ingredients</h2>
        <p>Generated recipes can add missing ingredients here.</p>
      </div>

      <div className="card list-card">
        {items.length === 0 && <p className="empty-state">No shopping items yet. Generate a recipe and add missing ingredients.</p>}
        {items.map((item) => (
          <div className={`list-row ${item.checked ? "checked" : ""}`} key={item.id}>
            <button className="check-button" type="button" onClick={() => dispatch(toggleShoppingItem(item.id))} aria-label={`Toggle ${item.name}`}>
              {item.checked && <FontAwesomeIcon icon={faCheck} />}
            </button>
            <strong>{item.name}</strong>
            <button className="icon-button danger" type="button" onClick={() => dispatch(removeShoppingItem(item.id))} aria-label={`Remove ${item.name}`}>
              <FontAwesomeIcon icon={faTrash} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
